400:         comptime assert(meta.fieldIndex(SuperBlockHeader, "checksum") == 0);
401:         comptime assert(meta.fieldIndex(SuperBlockHeader, "checksum_padding") == 1);
402:         comptime assert(meta.fieldIndex(SuperBlockHeader, "copy") == 2);
403: 
404:         const checksum_size = @sizeOf(@TypeOf(superblock.checksum));
405:         comptime assert(checksum_size == @sizeOf(u128));
406: 
407:         const checksum_padding_size = @sizeOf(@TypeOf(superblock.checksum_padding));
408:         comptime assert(checksum_padding_size == @sizeOf(u128));
409: 
410:         const copy_size = @sizeOf(@TypeOf(superblock.copy));
411:         comptime assert(copy_size == 2);
