376: /// Compare two values by directly comparing the underlying memory.
377: ///
378: /// Assert at compile time that this is a reasonable thing to do for a given `T`. That is, check
379: /// that:
380: ///   - `T` doesn't have any non-deterministic padding,
381: ///   - `T` doesn't embed any pointers.
382: pub fn equal_bytes(comptime T: type, a: *const T, b: *const T) bool {
383:     comptime assert(has_unique_representation(T));
384:     comptime assert(!has_pointers(T));
385:     comptime assert(@sizeOf(T) * 8 == @bitSizeOf(T));
386: 
387:     // Pick the biggest "word" for word-wise comparison, and don't try to early-return on the first
388:     // mismatch, so that a compiler can vectorize the loop.
389: 
390:     const Word = comptime for (.{ u64, u32, u16, u8 }) |Word| {
391:         if (@alignOf(T) >= @alignOf(Word) and @sizeOf(T) % @sizeOf(Word) == 0) break Word;
392:     } else unreachable;
393: 
394:     // NOTE: Alignment is intentionally downcast here to work around a Zig code generation bug
395:     // described in  https://codeberg.org/ziglang/zig/issues/31473.
396:     // TODO: Remove the following two lines once the issue is fixed.
397:     const a_bytes: *align(@alignOf(Word)) const [@sizeOf(T)]u8 =
398:         @alignCast(std.mem.asBytes(a));
399:     const b_bytes: *align(@alignOf(Word)) const [@sizeOf(T)]u8 =
400:         @alignCast(std.mem.asBytes(b));
401: 
402:     const a_words = std.mem.bytesAsSlice(Word, a_bytes);
403:     const b_words = std.mem.bytesAsSlice(Word, b_bytes);
404: 
405:     assert(a_words.len == b_words.len);
406: 
407:     var total: Word = 0;
408:     for (a_words, b_words) |a_word, b_word| {
409:         total |= a_word ^ b_word;
410:     }
411: 
412:     return total == 0;
413: }
