415: fn has_pointers(comptime T: type) bool {
416:     switch (@typeInfo(T)) {
417:         .pointer => return true,
418:         // Be conservative.
419:         else => return true,
420: 
421:         .bool, .int, .@"enum" => return false,
422: 
423:         .array => |info| return comptime has_pointers(info.child),
424:         .@"struct" => |info| {
425:             inline for (info.fields) |field| {
426:                 if (comptime has_pointers(field.type)) return true;
427:             }
428:             return false;
429:         },
430:     }
431: }
