941: /// Like std.fmt.bufPrint, but checks, at compile time, that the buffer is sufficiently large.
942: pub fn array_print(
943:     comptime n: usize,
944:     buffer: *[n]u8,
945:     comptime fmt: []const u8,
946:     args: anytype,
947: ) []const u8 {
948:     const Args = @TypeOf(args);
949:     const ArgsStruct = @typeInfo(Args).@"struct";
950:     comptime assert(ArgsStruct.is_tuple);
951: 
952:     comptime {
953:         var args_worst_case: Args = undefined;
954:         for (ArgsStruct.fields, 0..) |field, index| {
955:             const arg_worst_case = switch (field.type) {
956:                 u8, u16, u32, u64, u128 => std.math.maxInt(field.type),
957:                 else => @compileError("array_print: unsupported type: " ++ @typeName(field.type)),
958:             };
959:             args_worst_case[index] = arg_worst_case;
960:         }
961:         const buffer_size = std.fmt.count(fmt, args_worst_case);
962:         assert(n >= buffer_size); // array_print buffer too small
963:     }
964: 
965:     return std.fmt.bufPrint(buffer, fmt, args) catch |err| switch (err) {
966:         error.NoSpaceLeft => unreachable,
967:     };
968: }
