1145: pub fn term_from_status(status: u32) std.process.Child.Term {
1146:     const Term = std.process.Child.Term;
1147:     return if (std.posix.W.IFEXITED(status))
1148:         Term{ .Exited = std.posix.W.EXITSTATUS(status) }
1149:     else if (std.posix.W.IFSIGNALED(status))
