150:     /// An anonymous struct instance which contains the following:
151:     ///
152:     /// - ids: { .tree = u16 }:
153:     ///     An anonymous struct which maps each of the groove's trees to a stable, forest-unique,
154:     ///     tree identifier.
155:     ///
156:     /// - batch_value_count_max: { .field = usize }:
157:     ///     An anonymous struct which contains, for each field of `Object`,
158:     ///     the maximum number of values per table per batch for the corresponding index tree.
159:     ///
160:     /// - ignored: [][]const u8:
161:     ///     An array of fields on the Object type that should not be given index trees
162:     ///
163:     /// - optional: [][]const u8:
164:     ///     An array of fields that should *not* index zero values.
165:     ///
166:     /// - derived: { .field = *const fn (*const Object) ?DerivedType }:
167:     ///     An anonymous struct which contain fields that don't exist on the Object
168:     ///     but can be derived from an Object instance using the field's corresponding function.
169:     ///
170:     /// - orphaned_ids: bool:
171:     ///     Whether Groove should store objectless `id`s to prevent their reuse.
172:     ///     Should be `true` only if the object contains an `id` field.
173:     ///
174:     /// - objects_cache: bool:
175:     ///     Whether Groove should have an ObjectCache.
176:     ///     Should be `false` only if both `prefetch_entries_for_update_max` and
177:     ///     `prefetch_entries_for_read_max` are set to 0.
178:     comptime groove_options: anytype,
179: ) type {
180:     @setEvalBranchQuota(64_000);
181: 
182:     const has_id = @hasField(Object, "id");
183:     comptime if (has_id) assert(@FieldType(Object, "id") == u128);
184:     comptime if (groove_options.orphaned_ids) assert(has_id);
185: 
186:     assert(@hasField(Object, "timestamp"));
187:     assert(@FieldType(Object, "timestamp") == u64);
188: 
189:     comptime var index_fields: []const std.builtin.Type.StructField = &.{};
190: 
191:     const primary_field = if (has_id) "id" else "timestamp";
192:     const PrimaryKey = if (has_id) u128 else u64;
193: 
194:     // Generate index LSM trees from the struct fields.
195:     for (std.meta.fields(Object)) |field| {
196:         // See if we should ignore this field from the options.
197:         //
198:         // By default, we ignore the "timestamp" field since it's a special identifier.
199:         // Since the "timestamp" is ignored by default, it shouldn't be provided
200:         // in groove_options.ignored.
201:         comptime var ignored =
202:             mem.eql(u8, field.name, "timestamp") or mem.eql(u8, field.name, "id");
203:         for (groove_options.ignored) |ignored_field_name| {
204:             comptime assert(!std.mem.eql(u8, ignored_field_name, "timestamp"));
205:             comptime assert(!std.mem.eql(u8, ignored_field_name, "id"));
206:             ignored = ignored or std.mem.eql(u8, field.name, ignored_field_name);
207:         }
208: 
209:         if (!ignored) {
210:             const table_value_count_max = constants.lsm_compaction_ops *
211:                 @field(groove_options.batch_value_count_max, field.name);
212:             const IndexTree = IndexTreeType(Storage, field.type, table_value_count_max);
213:             index_fields = index_fields ++ [_]std.builtin.Type.StructField{
214:                 .{
215:                     .name = field.name,
216:                     .type = IndexTree,
217:                     .default_value_ptr = null,
218:                     .is_comptime = false,
219:                     .alignment = @alignOf(IndexTree),
220:                 },
221:             };
222:         }
223:     }
224: 
225:     // Generate IndexTrees for fields derived from the Value in groove_options.
226:     const derived_fields = std.meta.fields(@TypeOf(groove_options.derived));
227:     for (derived_fields) |field| {
228:         // Get the function info for the derived field.
229:         const derive_func = @field(groove_options.derived, field.name);
230:         const derive_func_info = @typeInfo(@TypeOf(derive_func)).@"fn";
231: 
232:         // Make sure it has only one argument.
233:         if (derive_func_info.params.len != 1) {
234:             @compileError("expected derive fn to take in *const " ++ @typeName(Object));
235:         }
236: 
237:         // Make sure the function takes in a reference to the Value:
238:         const derive_arg = derive_func_info.params[0];
239:         if (derive_arg.is_generic) @compileError("expected derive fn arg to not be generic");
240:         if (derive_arg.type != *const Object) {
241:             @compileError("expected derive fn to take in *const " ++ @typeName(Object));
242:         }
243: 
244:         // Get the return value from the derived field as the DerivedType.
245:         if (derive_func_info.return_type == null) {
246:             @compileError("expected derive fn to return valid tree index type");
247:         }
248: 
249:         const derive_return_type = @typeInfo(derive_func_info.return_type.?);
250:         if (derive_return_type != .optional) {
251:             @compileError("expected derive fn to return optional tree index type");
252:         }
253: 
254:         const DerivedType = derive_return_type.optional.child;
255:         const table_value_count_max = constants.lsm_compaction_ops *
256:             @field(groove_options.batch_value_count_max, field.name);
257:         const IndexTree = IndexTreeType(Storage, DerivedType, table_value_count_max);
258: 
259:         index_fields = index_fields ++ [_]std.builtin.Type.StructField{
260:             .{
261:                 .name = field.name,
262:                 .type = IndexTree,
263:                 .default_value_ptr = null,
264:                 .is_comptime = false,
265:                 .alignment = @alignOf(IndexTree),
266:             },
267:         };
268:     }
269: 
270:     comptime var index_options_fields: [index_fields.len]std.builtin.Type.StructField = undefined;
271:     for (index_fields, 0..) |index_field, i| {
272:         const IndexTree = index_field.type;
273:         index_options_fields[i] = .{
274:             .name = index_field.name,
275:             .type = IndexTree.Options,
276:             .default_value_ptr = null,
277:             .is_comptime = false,
278:             .alignment = @alignOf(IndexTree.Options),
279:         };
280:     }
281: 
282:     // Verify that every tree referenced by "optional" corresponds to an actual field.
283:     for (groove_options.optional) |field_name| {
284:         if (!@hasField(Object, field_name)) {
285:             std.debug.panic("optional: unrecognized field name: {s}", .{field_name});
286:         }
287:     }
