289:     const ObjectTreeHelper = ObjectTreeHelperType(Object);
290: 
291:     const _ObjectTree = blk: {
292:         const table_value_count_max = constants.lsm_compaction_ops *
293:             groove_options.batch_value_count_max.timestamp;
294:         const Table = TableType(
295:             u64, // key = timestamp
296:             Object,
297:             ObjectTreeHelper.key_from_value,
