1001:         /// The replica calls view_change():
1002:         ///
1003:         /// - to persist its view/log_view — it cannot advertise either value until it is certain
1004:         ///   they will never backtrack.
1005:         /// - to update checkpoint during sync
1006:         ///
1007:         /// The update must advance view/log_view (monotonically increasing) or checkpoint.
1008:         // TODO: the current naming confusing and needs changing: during sync, this function doesn't
1009:         //       necessary advance the view.
1010:         pub fn view_change(
1011:             superblock: *SuperBlock,
1012:             callback: *const fn (context: *Context) void,
1013:             context: *Context,
1014:             update: UpdateViewChange,
1015:         ) void {
1016:             assert(superblock.opened);
1017:             assert(superblock.staging.vsr_state.commit_max <= update.commit_max);
1018:             assert(superblock.staging.vsr_state.view <= update.view);
1019:             assert(superblock.staging.vsr_state.log_view <= update.log_view);
1020:             assert(superblock.staging.vsr_state.log_view < update.log_view or
1021:                 superblock.staging.vsr_state.view < update.view or
1022:                 update.sync_checkpoint != null);
1023:             assert((update.headers.command == .view and update.log_view == update.view) or
1024:                 (update.headers.command == .join_view and update.log_view < update.view));
1025:             assert(
1026:                 superblock.staging.vsr_state.checkpoint.header.op <= update.headers.array.get(0).op,
1027:             );
1028: 
1029:             update.headers.verify();
1030:             assert(update.view >= update.log_view);
1031: 
1032:             var vsr_state = superblock.staging.vsr_state;
1033:             vsr_state.commit_max = update.commit_max;
1034:             vsr_state.log_view = update.log_view;
1035:             vsr_state.view = update.view;
1036:             if (update.sync_checkpoint) |*sync_checkpoint| {
1037:                 assert(superblock.staging.vsr_state.checkpoint.header.op <
1038:                     sync_checkpoint.checkpoint.header.op);
1039: 
1040:                 const checkpoint_next = vsr.Checkpoint.checkpoint_after(
1041:                     superblock.staging.vsr_state.checkpoint.header.op,
1042:                 );
1043:                 const checkpoint_next_next = vsr.Checkpoint.checkpoint_after(checkpoint_next);
1044: 
1045:                 if (sync_checkpoint.checkpoint.header.op == checkpoint_next) {
1046:                     assert(sync_checkpoint.checkpoint.parent_checkpoint_id ==
1047:                         superblock.staging.checkpoint_id());
1048:                 } else if (sync_checkpoint.checkpoint.header.op == checkpoint_next_next) {
1049:                     assert(sync_checkpoint.checkpoint.grandparent_checkpoint_id ==
1050:                         superblock.staging.checkpoint_id());
1051:                 }
1052: 
1053:                 vsr_state.checkpoint = sync_checkpoint.checkpoint.*;
1054:                 vsr_state.sync_op_min = sync_checkpoint.sync_op_min;
1055:                 vsr_state.sync_op_max = sync_checkpoint.sync_op_max;
1056:             }
1057:             assert(superblock.staging.vsr_state.would_be_updated_by(vsr_state));
1058: 
1059:             context.* = .{
1060:                 .superblock = superblock,
1061:                 .callback = callback,
1062:                 .caller = .view_change,
1063:                 .vsr_state = vsr_state,
1064:                 .view_headers = update.headers.*,
1065:             };
1066:             superblock.log_context(context);
1067:             superblock.acquire(context);
1068:         }
