1098:             superblock.staging.parent = superblock.staging.checksum;
1099:             superblock.staging.vsr_state = context.vsr_state.?;
1100: 
1101:             if (context.view_headers) |*headers| {
1102:                 assert(context.caller.updates_view_headers());
1103: 
1104:                 superblock.staging.view_headers_count = headers.array.count_as(u32);
1105:                 stdx.copy_disjoint(
1106:                     .exact,
