1124:         fn write_header(superblock: *SuperBlock, context: *Context) void {
1125:             assert(superblock.queue_head == context);
1126: 
1127:             // We update the working superblock for a checkpoint/format/view_change:
1128:             // open() does not update the working superblock, since it only writes to repair.
1129:             if (context.caller == .open) {
1130:                 assert(superblock.staging.sequence == superblock.working.sequence);
1131:             } else {
1132:                 assert(superblock.staging.sequence == superblock.working.sequence + 1);
1133:                 assert(superblock.staging.parent == superblock.working.checksum);
1134:             }
1135: 
1136:             // The superblock cluster and replica should never change once formatted:
1137:             assert(superblock.staging.cluster == superblock.working.cluster);
1138:             assert(superblock.staging.vsr_state.replica_id ==
1139:                 superblock.working.vsr_state.replica_id);
1140: 
1141:             const storage_size = superblock.staging.vsr_state.checkpoint.storage_size;
1142:             assert(storage_size >= data_file_size_min);
1143:             assert(storage_size <= constants.storage_size_limit_max);
1144: 
1145:             assert(context.copy.? < constants.superblock_copies);
1146:             superblock.staging.copy = context.copy.?;
1147:             // Updating the copy number should not affect the checksum, which was previously set:
1148:             assert(superblock.staging.valid_checksum());
1149: 
1150:             const buffer = mem.asBytes(superblock.staging);
1151:             const offset = superblock_copy_size * @as(u32, context.copy.?);
1152: 
1153:             log.debug("{?}: {s}: write_header: " ++
1154:                 "checksum={x:0>32} sequence={} copy={} size={} offset={}", .{
1155:                 superblock.replica_index,
1156:                 @tagName(context.caller),
1157:                 superblock.staging.checksum,
1158:                 superblock.staging.sequence,
1159:                 context.copy.?,
1160:                 buffer.len,
1161:                 offset,
1162:             });
1163: 
1164:             SuperBlock.assert_bounds(offset, buffer.len);
1165: 
1166:             superblock.storage.write_sectors(
1167:                 write_header_callback,
1168:                 &context.write,
1169:                 buffer,
1170:                 .superblock,
1171:                 offset,
1172:             );
1173:         }
