1175:         fn write_header_callback(write: *Storage.Write) void {
1176:             const context: *Context = @alignCast(@fieldParentPtr("write", write));
1177:             const superblock = context.superblock;
1178:             const copy = context.copy.?;
1179: 
1180:             assert(superblock.queue_head == context);
1181: 
1182:             assert(copy < constants.superblock_copies);
1183:             assert(copy == superblock.staging.copy);
1184: 
1185:             if (context.caller == .open) {
1186:                 context.copy = null;
1187:                 superblock.repair(context);
1188:                 return;
1189:             }
1190: 
1191:             if (copy + 1 == constants.superblock_copies) {
