210:         pub fn on_message(self: *Client, message: *Message) void {
211:             assert(!self.evicted);
212: 
213:             // Switch on the header type so that we don't log opaque bytes for the per-command data.
214:             switch (message.header.into_any()) {
215:                 inline else => |header| {
216:                     log.debug("{}: on_message: {}", .{ self.id, header });
