222:                 return;
223:             }
224:             if (message.header.cluster != self.cluster) {
225:                 log.warn("{}: on_message: wrong cluster (cluster should be {}, not {})", .{
226:                     self.id,
227:                     self.cluster,
228:                     message.header.cluster,
229:                 });
230:                 return;
231:             }
232:             switch (message.into_any()) {
233:                 .pong_client => |m| self.on_pong_client(m),
234:                 .reply => |m| self.on_reply(m),
235:                 .eviction => |m| self.on_eviction(m),
236:                 else => {
237:                     log.warn("{}: on_message: ignoring misdirected {s} message", .{
238:                         self.id,
239:                         @tagName(message.header.command),
240:                     });
241:                     return;
242:                 },
