261:         /// Registers a session with the cluster for the client, if this has not yet been done.
262:         pub fn register(self: *Client, callback: Request.RegisterCallback, user_data: u128) void {
263:             assert(!self.evicted);
264:             assert(self.request_inflight == null);
265:             assert(self.request_number == 0);
266: 
267:             const message = self.get_message().build(.request);
268:             errdefer self.release_message(message.base());
269: 
270:             // We will set parent, session, view and checksums only when sending for the first time:
271:             message.header.* = .{
272:                 .size = @sizeOf(Header) + @sizeOf(vsr.RegisterRequest),
273:                 .client = self.id,
274:                 .request = self.request_number,
275:                 .cluster = self.cluster,
276:                 .command = .request,
277:                 .operation = .register,
278:                 .release = self.release,
279:                 .previous_request_latency = 0,
280:                 // During AOF recovery, if we were to pass timestamp=0, the primary would assign the
281:                 // timestamp. Instead, we send a fixed bogus timestamp (1), to ensure that AOF
282:                 // recovery is deterministic.
283:                 .timestamp = @intFromBool(self.aof_recovery),
284:             };
285: 
286:             std.mem.bytesAsValue(
287:                 vsr.RegisterRequest,
288:                 message.body_used()[0..@sizeOf(vsr.RegisterRequest)],
289:             ).* = .{
290:                 .batch_size_limit = 0,
291:             };
292: 
293:             assert(self.request_number == 0);
294:             self.request_number += 1;
295: 
296:             log.debug(
297:                 "{}: register: registering a session with the cluster user_data={}",
298:                 .{ self.id, user_data },
299:             );
300: 
301:             self.request_inflight = .{
302:                 .message = message,
303:                 .user_data = user_data,
304:                 .callback = .{ .register = callback },
305:             };
306:             self.send_request_for_the_first_time(message);
307:         }
