309:         /// Sends a request message with the operation and events payload to the replica.
310:         /// There must be no other request message currently inflight.
311:         pub fn request(
312:             self: *Client,
313:             callback: Request.Callback,
314:             user_data: u128,
315:             operation: Operation,
316:             events: []const u8,
317:         ) void {
318:             assert(!self.evicted);
319:             assert(self.request_inflight == null);
320:             assert(self.request_number > 0);
321: 
322:             const event_size = operation.event_size();
323:             assert(events.len <= constants.message_body_size_max);
324:             assert(events.len <= self.batch_size_limit.?);
325:             assert(events.len % event_size == 0);
326: 
327:             const message = self.get_message().build(.request);
328:             errdefer self.release_message(message.base());
329: 
330:             message.header.* = .{
331:                 .client = self.id,
332:                 .request = 0, // Set inside `raw_request` down below.
333:                 .cluster = self.cluster,
334:                 .command = .request,
335:                 .release = self.release,
336:                 .operation = operation.to_vsr(),
337:                 .size = @intCast(@sizeOf(Header) + events.len),
338:                 .previous_request_latency = 0,
339:             };
340: 
341:             stdx.copy_disjoint(.exact, u8, message.body_used(), events);
342:             self.raw_request(callback, user_data, message);
343:         }
