463:         fn on_pong_client(self: *Client, pong: *const Message.PongClient) void {
464:             assert(pong.header.command == .pong_client);
465:             assert(pong.header.cluster == self.cluster);
466: 
467:             if (pong.header.view > self.view) {
468:                 log.debug("{}: on_pong: newer view={}..{}", .{
469:                     self.id,
470:                     self.view,
471:                     pong.header.view,
472:                 });
473:                 self.view = pong.header.view;
474:                 // Even if there is a request in flight, don't try to retransmit it immediately
475:                 // after a view change. Instead, ride the on_request_timeout normally to reduce the
476:                 // size of thundering herd.
477:                 maybe(self.request_inflight != null);
478:             }
