480:             const ping_timestamp_monotonic = pong.header.ping_timestamp_monotonic;
481:             const pong_timestamp_monotonic = self.time.monotonic().ns;
482:             if (ping_timestamp_monotonic <= pong_timestamp_monotonic) {
483:                 self.replica_round_trip_times_ns[pong.header.replica] =
484:                     pong_timestamp_monotonic - ping_timestamp_monotonic;
485: 
486:                 var round_trip_times_ns = stdx.BoundedArrayType(u64, constants.replicas_max){};
487:                 for (self.replica_round_trip_times_ns) |round_trip_time_ns| {
488:                     if (round_trip_time_ns) |rtt_ns| {
489:                         round_trip_times_ns.push(rtt_ns);
490:                     }
491:                 }
492:                 std.mem.sort(u64, round_trip_times_ns.slice(), {}, std.sort.asc(u64));
493:                 assert(round_trip_times_ns.count() > 0);
494: 
495:                 const rtt_median_ns =
496:                     round_trip_times_ns.get(@divFloor(round_trip_times_ns.count(), 2));
497:                 self.request_timeout.set_rtt_ns(rtt_median_ns);
498:             } else {
499:                 log.debug("{}: on_pong: monotonic timestamp regressed {}..{} replica={}", .{
500:                     self.id,
501:                     ping_timestamp_monotonic,
502:                     pong_timestamp_monotonic,
