449:             callback(manifest_log);
450:         }
451: 
452:         /// Appends an insert/update/remove of a table to a level.
453:         ///
454:         /// A move is only recorded as an update, there is no remove from the previous level, since
455:         /// this is safer (no potential to get the event order wrong) and reduces fragmentation.
456:         pub fn append(manifest_log: *ManifestLog, table: *const TableInfo) void {
457:             maybe(manifest_log.opened);
458:             maybe(manifest_log.reading);
459:             assert(!manifest_log.writing);
460: 
461:             switch (table.label.event) {
462:                 .reserved => unreachable,
463:                 .insert => assert(manifest_log.table_extents.get(table.address) == null),
464:                 // For updates + removes, the table must have previously been inserted into the log:
465:                 .update => assert(manifest_log.table_extents.get(table.address) != null),
466:                 .remove => assert(manifest_log.table_extents.get(table.address) != null),
467:             }
468: 
469:             manifest_log.append_internal(table);
470:         }
471: 
472:         /// The table extent must be updated immediately when appending, without delay.
473:         /// Otherwise, ManifestLog.compact() may append a stale version over the latest.
474:         ///
475:         /// append_internal() is used for both:
476:         /// - External appends, e.g. events created due to table compaction.
477:         /// - Internal appends, e.g. events recycled by manifest compaction.
478:         fn append_internal(manifest_log: *ManifestLog, table: *const TableInfo) void {
479:             assert(manifest_log.opened);
480:             assert(!manifest_log.writing);
481:             maybe(manifest_log.reading);
482:             assert(manifest_log.grid_reservation != null);
483:             assert(table.label.level < constants.lsm_levels);
484:             assert(table.address > 0);
485:             assert(table.snapshot_min > 0);
486:             assert(table.snapshot_max > table.snapshot_min);
487: 
488:             if (manifest_log.entry_count == 0) {
489:                 assert(manifest_log.blocks.count == manifest_log.blocks_closed);
490:                 manifest_log.acquire_block();
491:             } else if (manifest_log.entry_count > 0) {
492:                 assert(manifest_log.blocks.count > 0);
493:             }
494: 
495:             assert(manifest_log.entry_count < schema.ManifestNode.entry_count_max);
496:             assert(manifest_log.blocks.count - manifest_log.blocks_closed == 1);
497: 
498:             log.debug(
499:                 "{}: {s}: level={} tree={} checksum={x:0>32} address={} snapshot={}..{}",
500:                 .{
501:                     manifest_log.superblock.replica_index.?,
502:                     @tagName(table.label.event),
503:                     table.label.level,
504:                     table.tree_id,
505:                     table.checksum,
506:                     table.address,
507:                     table.snapshot_min,
508:                     table.snapshot_max,
509:                 },
510:             );
511: 
512:             const block: BlockPtr = manifest_log.blocks.tail().?;
513:             const entry = manifest_log.entry_count;
514:             block_builder_schema.tables(block)[entry] = table.*;
515: 
516:             const block_header =
517:                 mem.bytesAsValue(vsr.Header.Block, block[0..@sizeOf(vsr.Header)]);
518:             const block_address = block_header.address;
519: 
520:             switch (table.label.event) {
521:                 .reserved => unreachable,
522:                 .insert,
523:                 .update,
524:                 => {
525:                     const extent = manifest_log.table_extents.getOrPutAssumeCapacity(table.address);
526:                     if (!extent.found_existing) {
527:                         assert(table.label.event == .insert);
528: 
529:                         // When inserting, check that the insertion didn't cause the number of
530:                         // tables to exceed `forest_table_count_max`.
531:                         manifest_log.check_tables_count();
532:                     } else {
533:                         maybe(table.label.event == .insert); // (Compaction.)
534:                     }
535:                     extent.value_ptr.* = .{ .block = block_address, .entry = entry };
536:                 },
537:                 .remove => assert(manifest_log.table_extents.remove(table.address)),
538:             }
539: 
540:             manifest_log.entry_count += 1;
541:             if (manifest_log.entry_count == schema.ManifestNode.entry_count_max) {
542:                 manifest_log.close_block();
543:                 assert(manifest_log.entry_count == 0);
544:             }
545:         }
546: 
547:         fn check_tables_count(manifest_log: *ManifestLog) void {
548:             const tables_count = manifest_log.table_extents.count();
549:             if (tables_count > manifest_log.forest_table_count_max) {
550:                 vsr.fatal(
551:                     .forest_tables_count_would_exceed_limit,
552:                     "forest_tables_count would exceed limit " ++
553:                         "(tables_count={} tables_max={}) - " ++
554:                         "please contact the team directly who will be able to assist",
555:                     .{ tables_count, manifest_log.forest_table_count_max },
556:                 );
557:             }
558:         }
