623:         fn on_ping_timeout(self: *Client) void {
624:             self.ping_timeout.reset();
625: 
626:             const ping = Header.PingClient{
627:                 .command = .ping_client,
628:                 .cluster = self.cluster,
629:                 .release = self.release,
630:                 .client = self.id,
631:                 .ping_timestamp_monotonic = self.time.monotonic().ns,
632:             };
633: 
634:             self.send_header_to_replicas(ping.frame_const());
635:         }
636: 
637:         // Possible reasons for a timeout:
638:         // - the cluster is overloaded and takes too long to respond
639:         // - the request message got dropped by the network
640:         // - there was a view change, and we are not speaking to the primary
641:         fn on_request_timeout(self: *Client) void {
642:             self.request_timeout.backoff(&self.prng); // Reduce the load.
643: 
644:             const message = self.request_inflight.?.message;
645:             assert(message.header.command == .request);
646:             assert(message.header.request < self.request_number);
647:             assert(message.header.checksum == self.parent);
648:             assert(message.header.session == self.session);
649: 
650:             log.debug("{}: on_request_timeout: resending request={} checksum={x:0>32}", .{
651:                 self.id,
652:                 message.header.request,
653:                 message.header.checksum,
654:             });
655: 
656:             self.send_request_with_hedging(message);
657:         }
658: 
659:         /// The caller owns the returned message, if any, which has exactly 1 reference.
660:         fn create_message_from_header(self: *Client, header: *const Header) *Message {
661:             assert(header.cluster == self.cluster);
662:             assert(header.size == @sizeOf(Header));
663: 
664:             const message = self.message_bus.get_message(null);
665:             defer self.message_bus.unref(message);
666: 
667:             message.header.* = header.*;
668:             message.header.set_checksum_body(message.body_used());
669:             message.header.set_checksum();
670: 
671:             return message.ref();
672:         }
673: 
674:         fn send_header_to_replicas(self: *Client, header: *const Header) void {
675:             const message = self.create_message_from_header(header);
676:             defer self.message_bus.unref(message);
677: 
678:             self.send_message_to_replicas(message);
679:         }
