130:     ///   "All single-phase or posted events today."
131:     ///
132:     ///  Value   | Description
133:     /// ---------|-----------------------------------------------------
134:     /// `none`   | This event is a regular transfer.
135:     /// `pending`| This event is a pending transfer.
136:     /// `posted` | This event posted a pending transfer.
137:     /// `voided` | This event voided a pending transfer.
138:     /// `expired`| This event expired a pending transfer,
139:     ///            the `timestamp` does not relate to a transfer.
140:     ///
141:     /// See `transfer_pending_id` for tracking the pending transfer.
142:     /// It will be `zero` for `none` and `pending`.
143:     transfer_pending_status: TransferPendingStatus,
144:     reserved: [11]u8 = @splat(0),
145: 
146:     /// Previous schema before the changes introduced by PR #2507.
147:     const Former = extern struct {
148:         dr_account_id: u128,
149:         dr_debits_pending: u128,
150:         dr_debits_posted: u128,
151:         dr_credits_pending: u128,
152:         dr_credits_posted: u128,
153:         cr_account_id: u128,
154:         cr_debits_pending: u128,
155:         cr_debits_posted: u128,
156:         cr_credits_pending: u128,
157:         cr_credits_posted: u128,
158:         timestamp: u64,
159:         reserved: [88]u8 = @splat(0),
160: 
161:         comptime {
162:             assert(stdx.no_padding(Former));
163:             assert(@sizeOf(Former) == @sizeOf(AccountEvent));
164:             assert(@alignOf(Former) == @alignOf(AccountEvent));
165: 
166:             // Asserting the fields are identical.
167:             for (std.meta.fields(Former)) |field_former| {
168:                 if (std.mem.eql(u8, field_former.name, "reserved")) continue;
169:                 const field = std.meta.fields(AccountEvent)[
170:                     std.meta.fieldIndex(
171:                         AccountEvent,
172:                         field_former.name,
173:                     ).?
174:                 ];
175:                 assert(field_former.type == field.type);
176:                 assert(field_former.alignment == field.alignment);
177:                 assert(@offsetOf(AccountEvent, field_former.name) ==
178:                     @offsetOf(Former, field_former.name));
179:             }
180:         }
181:     };
182: 
183:     /// Checks the object and returns whether it was created
184:     /// using the current or the former schema.
185:     fn schema(self: *const AccountEvent) union(enum) {
186:         current,
187:         former: *const AccountEvent.Former,
188:     } {
189:         assert(self.timestamp != 0);
190: 
191:         const former: *const AccountEvent.Former = @ptrCast(self);
192:         if (stdx.zeroed(&former.reserved)) {
193:             // In the former schema:
194:             // Balances for accounts without the `history` flag weren’t stored.
195:             // If neither side had the `history` flag, the entire object wasn’t stored.
196:             assert(former.dr_account_id != 0 or former.cr_account_id != 0);
197: 
198:             return .{ .former = former };
199:         }
200: 
201:         assert(self.dr_account_timestamp != 0);
202:         assert(self.dr_account_id != 0);
203:         assert(self.cr_account_timestamp != 0);
204:         assert(self.cr_account_id != 0);
205:         assert(self.ledger != 0);
206:         switch (self.transfer_pending_status) {
207:             .none, .pending => assert(self.transfer_pending_id == 0),
208:             .posted, .voided, .expired => assert(self.transfer_pending_id != 0),
209:         }
210:         assert(stdx.zeroed(&self.reserved));
211:         return .current;
212:     }
213: 
214:     comptime {
215:         assert(stdx.no_padding(AccountEvent));
216:         assert(@sizeOf(AccountEvent) == 256);
217:         assert(@alignOf(AccountEvent) == 16);
218:     }
219: };
