1: const std = @import("std");
2: const assert = std.debug.assert;
3: const log = std.log.scoped(.superblock_quorums);
4: 
5: const stdx = @import("stdx");
6: const maybe = stdx.maybe;
7: 
8: const superblock = @import("./superblock.zig");
9: const SuperBlockHeader = superblock.SuperBlockHeader;
10: 
11: pub const Options = struct {
12:     superblock_copies: u8,
13: };
14: 
15: pub fn QuorumsType(comptime options: Options) type {
16:     return struct {
17:         const Quorums = @This();
18: 
19:         const Quorum = struct {
20:             header: *const SuperBlockHeader,
21:             valid: bool = false,
22:             /// Track which copies are a member of the quorum.
23:             /// Used to ignore duplicate copies of a header when determining a quorum.
24:             copies: QuorumCount = .{},
25:             /// An integer value indicates the copy index found in the corresponding slot.
26:             /// A `null` value indicates that the copy is invalid or not a member of the working
27:             /// quorum. All copies belong to the same (valid, working) quorum.
28:             slots: [options.superblock_copies]?u8 = @splat(null),
29: 
30:             pub fn repairs(quorum: Quorum) RepairIterator {
31:                 assert(quorum.valid);
32:                 return .{ .slots = quorum.slots };
33:             }
34:         };
35: 
36:         pub const QuorumCount = stdx.BitSetType(options.superblock_copies);
37: 
38:         pub const Error = error{
39:             Fork,
40:             NotFound,
41:             QuorumLost,
42:             ParentNotConnected,
43:             ParentSkipped,
44:             VSRStateNotMonotonic,
45:         };
46: 
47:         /// We use flexible quorums for even quorums with write quorum > read quorum, for example:
48:         /// * When writing, we must verify that at least 3/4 copies were written.
49:         /// * At startup, we must verify that at least 2/4 copies were read.
50:         ///
51:         /// This ensures that our read and write quorums will intersect.
52:         /// Using flexible quorums in this way increases resiliency of the superblock.
53:         pub const Threshold = enum {
54:             verify,
55:             open,
56:             // Working these threshold out by formula is easy to get wrong, so enumerate them:
57:             // The rule is that the write quorum plus the read quorum must be exactly copies + 1.
58: 
59:             pub fn count(threshold: Threshold) u8 {
60:                 return switch (threshold) {
61:                     .verify => switch (options.superblock_copies) {
62:                         4 => 3,
63:                         6 => 4,
64:                         8 => 5,
65:                         else => unreachable,
66:                     },
67:                     // The open quorum must allow for at least two copy faults, because we update
68:                     // copies in place, temporarily impairing one copy.
69:                     .open => switch (options.superblock_copies) {
70:                         4 => 2,
71:                         6 => 3,
72:                         8 => 4,
73:                         else => unreachable,
74:                     },
75:                 };
76:             }
77:         };
78: 
79:         array: [options.superblock_copies]Quorum = undefined,
80:         count: u8 = 0,
81: 
82:         /// Returns the working superblock according to the quorum with the highest sequence number.
83:         ///
84:         /// * When a member of the parent quorum is still present, verify that the highest quorum is
85:         ///   connected.
86:         /// * When there are 2 quorums: 1/4 new and 3/4 old, favor the 3/4 old since it is safer to
87:         ///   repair.
88:         ///   TODO Re-examine this now that there are no superblock trailers to worry about.
89:         pub fn working(
90:             quorums: *Quorums,
91:             copies: []const SuperBlockHeader,
92:             threshold: Threshold,
93:         ) Error!Quorum {
94:             assert(copies.len == options.superblock_copies);
95:             assert(threshold.count() >= 2 and threshold.count() <= 5);
96: 
97:             quorums.array = undefined;
98:             quorums.count = 0;
99: 
100:             for (copies, 0..) |*copy, index| quorums.count_copy(copy, index, threshold);
101: 
102:             std.mem.sort(Quorum, quorums.slice(), {}, sort_priority_descending);
103: 
104:             for (quorums.slice()) |quorum| {
105:                 if (quorum.copies.full()) {
106:                     log.debug("quorum: checksum={x:0>32} parent={x:0>32} sequence={} count={} " ++
107:                         "valid={}", .{
108:                         quorum.header.checksum,
109:                         quorum.header.parent,
110:                         quorum.header.sequence,
111:                         quorum.copies.count(),
112:                         quorum.valid,
113:                     });
114:                 } else {
115:                     log.warn("quorum: checksum={x:0>32} parent={x:0>32} sequence={} count={} " ++
116:                         "valid={}", .{
117:                         quorum.header.checksum,
118:                         quorum.header.parent,
119:                         quorum.header.sequence,
120:                         quorum.copies.count(),

120:                         quorum.copies.count(),
121:                         quorum.valid,
122:                     });
123:                 }
124:             }
125: 
126:             // No working copies of any sequence number exist in the superblock storage zone at all.
127:             if (quorums.slice().len == 0) return error.NotFound;
128: 
129:             // At least one copy or quorum exists.
130:             const b = quorums.slice()[0];
131: 
132:             // Verify that the remaining quorums are correctly sorted:
133:             for (quorums.slice()[1..]) |a| {
134:                 assert(sort_priority_descending({}, b, a));
135:                 assert(a.header.valid_checksum());
136:             }
137: 
138:             // Even the best copy with the most quorum still has inadequate quorum.
139:             if (!b.valid) return error.QuorumLost;
140: 
141:             // If a parent quorum is present (either complete or incomplete) it must be connected to
142:             // the new working quorum. The parent quorum can exist due to:
143:             // - a crash during checkpoint()/view_change() before writing all copies
144:             // - a lost or misdirected write
145:             // - a latent sector error that prevented a write
146:             for (quorums.slice()[1..]) |a| {
147:                 if (a.header.cluster != b.header.cluster) {
148:                     log.warn("superblock copy={} has cluster={} instead of {}", .{
149:                         a.header.copy,
150:                         a.header.cluster,
151:                         b.header.cluster,
152:                     });
153:                     continue;
154:                 }
155: 
156:                 if (a.header.vsr_state.replica_id != b.header.vsr_state.replica_id) {
157:                     log.warn("superblock copy={} has replica_id={} instead of {}", .{
158:                         a.header.copy,
159:                         a.header.vsr_state.replica_id,
160:                         b.header.vsr_state.replica_id,
161:                     });
162:                     continue;
163:                 }
164: 
165:                 if (a.header.sequence == b.header.sequence) {
166:                     // Two quorums, same cluster+replica+sequence, but different checksums.
167:                     // This shouldn't ever happen — but if it does, we can't safely repair.
168:                     assert(a.header.checksum != b.header.checksum);
169:                     return error.Fork;
170:                 }
171: 
172:                 if (a.header.sequence > b.header.sequence + 1) {
173:                     // We read sequences such as (2,2,2,4) — 2 isn't safe to use, but there isn't a
174:                     // valid quorum for 4 either.
175:                     return error.ParentSkipped;
176:                 }
177: 
178:                 if (a.header.sequence + 1 == b.header.sequence) {
179:                     assert(a.header.checksum != b.header.checksum);
180:                     assert(a.header.cluster == b.header.cluster);
181:                     assert(a.header.vsr_state.replica_id == b.header.vsr_state.replica_id);
182: 
183:                     if (a.header.checksum != b.header.parent) {
184:                         return error.ParentNotConnected;
185:                     } else if (!a.header.vsr_state.monotonic(b.header.vsr_state)) {
186:                         return error.VSRStateNotMonotonic;
187:                     } else {
188:                         assert(b.header.valid_checksum());
189: 
190:                         return b;
191:                     }
192:                 }
193:             }
194: 
195:             assert(b.header.valid_checksum());
196:             return b;
197:         }
