199:         fn count_copy(
200:             quorums: *Quorums,
201:             copy: *const SuperBlockHeader,
202:             slot: usize,
203:             threshold: Threshold,
204:         ) void {
205:             assert(slot < options.superblock_copies);
206:             assert(threshold.count() >= 2 and threshold.count() <= 5);
207: 
208:             if (!copy.valid_checksum()) {
209:                 log.warn("copy: {}/{}: invalid checksum", .{ slot, options.superblock_copies });
210:                 return;
211:             }
212: 
213:             if (copy.copy == slot) {
214:                 log.debug(
215:                     "copy: {}/{}: valid checksum={x:0>32} parent={x:0>32} sequence={}",
216:                     .{ slot, options.superblock_copies, copy.checksum, copy.parent, copy.sequence },
217:                 );
218:             } else {
219:                 // Either the entire copy was misdirected, or just the copy field is corrupted.
220:                 // We definitely still want to count the copy.
221:                 // We must just be careful to count it idempotently.
222:                 log.warn(
223:                     "copy: {}/{}: unexpected copy={} checksum={x:0>32} parent={x:0>32} sequence={}",
224:                     .{
225:                         slot,
226:                         options.superblock_copies,
227:                         copy.copy,
228:                         copy.checksum,
229:                         copy.parent,
230:                         copy.sequence,
231:                     },
232:                 );
233:             }
234: 
235:             var quorum = quorums.find_or_insert_quorum_for_copy(copy);
236:             assert(quorum.header.checksum == copy.checksum);
237:             assert(quorum.header.equal(copy));
238: 
239:             if (copy.copy >= options.superblock_copies) {
240:                 // This header is a valid member of the quorum, but with an unexpected copy number.
241:                 // The "SuperBlockHeader.copy" field is not protected by the checksum, so if that
242:                 // byte (and only that byte) is corrupted, the superblock is still valid — but we
243:                 // don't know for certain which copy this was supposed to be.
244:                 // We make the assumption that this was not a double-fault (corrupt + misdirect) —
245:                 // that is, the copy is in the correct slot, and its copy index is simply corrupt.
246:                 quorum.slots[slot] = @intCast(slot);
247:                 quorum.copies.set(slot);
248:             } else if (quorum.copies.is_set(copy.copy)) {
249:                 // Ignore the duplicate copy.
250:             } else {
251:                 maybe(slot != copy.copy);
252:                 quorum.slots[slot] = @intCast(copy.copy);
253:                 quorum.copies.set(copy.copy);
254:             }
255:             assert(quorum.copies.count() >= 1);
256: 
257:             quorum.valid = quorum.copies.count() >= threshold.count();
258:         }
259: 
260:         fn find_or_insert_quorum_for_copy(
261:             quorums: *Quorums,
262:             copy: *const SuperBlockHeader,
263:         ) *Quorum {
264:             assert(copy.valid_checksum());
265: 
266:             for (quorums.array[0..quorums.count]) |*quorum| {
267:                 if (copy.checksum == quorum.header.checksum) return quorum;
268:             } else {
269:                 quorums.array[quorums.count] = Quorum{ .header = copy };
270:                 quorums.count += 1;
271: 
272:                 return &quorums.array[quorums.count - 1];
273:             }
274:         }
275: 
276:         fn slice(quorums: *Quorums) []Quorum {
277:             return quorums.array[0..quorums.count];
278:         }
279: 
280:         fn sort_priority_descending(_: void, a: Quorum, b: Quorum) bool {

280:         fn sort_priority_descending(_: void, a: Quorum, b: Quorum) bool {
281:             assert(a.header.checksum != b.header.checksum);
282: 
283:             if (a.valid and !b.valid) return true;
284:             if (b.valid and !a.valid) return false;
285: 
286:             if (a.header.sequence > b.header.sequence) return true;
287:             if (b.header.sequence > a.header.sequence) return false;
288: 
289:             if (a.copies.count() > b.copies.count()) return true;
290:             if (b.copies.count() > a.copies.count()) return false;
291: 
292:             // The sort order must be stable and deterministic:
293:             return a.header.checksum > b.header.checksum;
294:         }
295: 
296:         /// Repair a quorum's copies in the safest known order.
297:         /// Repair is complete when every copy is on-disk (not necessarily in its home slot).
298:         ///
299:         /// We must be careful when repairing superblock headers to avoid endangering our quorum if
300:         /// an additional fault occurs. We primarily guard against torn header writes — preventing a
301:         /// misdirected write from derailing repair is far more expensive and complex — but they are
302:         /// likewise far less likely to occur.
303:         ///
304:         /// For example, consider this case:
305:         ///   0. Sequence is initially A.
306:         ///   1. Checkpoint sequence B.
307:         ///   2.   Write B₀ — ok.
308:         ///   3.   Write B₁ — misdirected to B₂'s slot.
309:         ///   4. Crash.
310:         ///   5. Recover with quorum B[B₀,A₁,B₁,A₃].
311:         /// If we repair the superblock quorum while only considering the valid copies (and not
312:         /// slots) the following scenario could occur:
313:         ///   6. We already have a valid B₀ and B₁, so begin writing B₂.
314:         ///   7. Crash, tearing the B₂ write.
315:         ///   8. Recover with quorum A[B₀,A₁,_,A₂].
316:         /// The working quorum backtracked from B to A!
317:         pub const RepairIterator = struct {
318:             /// An integer value indicates the copy index found in the corresponding slot.
319:             /// A `null` value indicates that the copy is invalid or not a member of the working
320:             /// quorum. All copies belong to the same (valid, working) quorum.
321:             slots: [options.superblock_copies]?u8,
322: 
323:             /// Returns the slot/copy to repair next.
324:             /// We never (deliberately) write a copy to a slot other than its own. This is simpler
325:             /// to implement, and also reduces risk when one of open()'s reads was misdirected.
326:             pub fn next(iterator: *RepairIterator) ?u8 {
327:                 // Corrupt copy indices have already been normalized.
328:                 for (iterator.slots) |slot| {
329:                     assert(slot == null or slot.? < options.superblock_copies);
330:                 }
331: 
332:                 // Set bits indicate that the corresponding copy was found at least once.
333:                 var copies_any: QuorumCount = .{};
334:                 // Set bits indicate that the corresponding copy was found more than once.
335:                 var copies_duplicate: QuorumCount = .{};
336: 
337:                 for (iterator.slots) |slot| {
338:                     if (slot) |copy| {
339:                         if (copies_any.is_set(copy)) copies_duplicate.set(copy);
340:                         copies_any.set(copy);
341:                     }
342:                 }
343: 
344:                 // In descending order, our priorities for repair are:
345:                 // 1. The slot holds no header, and the copy was not found anywhere.
346:                 // 2. The slot holds no header, but its copy was found elsewhere.
347:                 // 3. The slot holds a misdirected header, but that copy is in another slot as well.
348:                 var a: ?u8 = null;
349:                 var b: ?u8 = null;
350:                 var c: ?u8 = null;
351:                 for (iterator.slots, 0..) |slot, i| {
352:                     if (slot == null and !copies_any.is_set(i)) a = @intCast(i);
353:                     if (slot == null and copies_any.is_set(i)) b = @intCast(i);
354:                     if (slot) |slot_copy| {
355:                         if (slot_copy != i and copies_duplicate.is_set(slot_copy)) c = @intCast(i);
356:                     }
357:                 }
358: 
359:                 const repair = a orelse b orelse c orelse {
360:                     for (iterator.slots) |slot| assert(slot != null);
361:                     return null;
362:                 };
363: 
364:                 iterator.slots[repair] = repair;
365:                 return repair;
366:             }
367:         };
368:     };
369: }
