560:         fn flush(manifest_log: *ManifestLog, callback: Callback) void {
561:             assert(manifest_log.opened);
562:             assert(!manifest_log.reading);
563:             assert(!manifest_log.writing);
564:             assert(manifest_log.write_callback == null);
565: 
566:             log.debug("{}: flush: writing {} block(s)", .{
567:                 manifest_log.superblock.replica_index.?,
568:                 manifest_log.blocks_closed,
569:             });
570: 
571:             manifest_log.writing = true;
572:             manifest_log.write_callback = callback;
573: 
574:             for (0..manifest_log.blocks_closed) |_| manifest_log.write_block();
575:             assert(manifest_log.blocks_closed == manifest_log.writes_pending);
576: 
577:             if (manifest_log.writes_pending == 0) {
578:                 manifest_log.grid.on_next_tick(flush_next_tick_callback, &manifest_log.next_tick);
579:             }
580:         }
