582:         fn flush_next_tick_callback(next_tick: *Grid.NextTick) void {
583:             const manifest_log: *ManifestLog = @alignCast(@fieldParentPtr("next_tick", next_tick));
584:             assert(manifest_log.writing);
585: 
586:             manifest_log.flush_done();
587:         }
