589:         fn flush_done(manifest_log: *ManifestLog) void {
590:             assert(manifest_log.writing);
591:             assert(manifest_log.write_callback != null);
592:             assert(manifest_log.blocks_closed == 0);
593: 
594:             const callback = manifest_log.write_callback.?;
595:             manifest_log.write_callback = null;
596:             manifest_log.writing = false;
597:             callback(manifest_log);
598:         }
