600:         fn write_block(manifest_log: *ManifestLog) void {
601:             assert(manifest_log.opened);
602:             assert(manifest_log.writing);
603:             assert(manifest_log.blocks_closed > 0);
604:             assert(manifest_log.blocks_closed <= manifest_log.blocks.count);
605:             assert(manifest_log.writes_pending < manifest_log.blocks_closed);
606: 
607:             const block_index = manifest_log.writes_pending;
608:             const block = manifest_log.blocks.get_ptr(block_index).?;
609:             verify_block(block.*, null, null);
610: 
611:             const block_schema = schema.ManifestNode.from(block.*);
612:             assert(block_schema.entry_count > 0);
613: 
614:             const header = schema.header_from_block(block.*);
615:             assert(header.address > 0);
616: 
617:             if (block_index == manifest_log.blocks_closed - 1) {
618:                 // This might be the last block of a checkpoint, which can be a partial block.
619:                 assert(block_schema.entry_count <= schema.ManifestNode.entry_count_max);
620:             } else {
621:                 assert(block_schema.entry_count == schema.ManifestNode.entry_count_max);
622:             }
623: 
624:             log.debug("{}: write_block: checksum={x:0>32} address={} entries={}", .{
625:                 manifest_log.superblock.replica_index.?,
626:                 header.checksum,
627:                 header.address,
628:                 block_schema.entry_count,
629:             });
630: 
631:             const write = &manifest_log.writes[block_index];
632:             write.* = .{ .manifest_log = manifest_log };
633: 
634:             manifest_log.writes_pending += 1;
635:             manifest_log.grid.create_block(write_block_callback, &write.write, block);
636:         }
