638:         fn write_block_callback(grid_write: *Grid.Write) void {
639:             const write: *Write = @fieldParentPtr("write", grid_write);
640:             const manifest_log = write.manifest_log;
641:             assert(manifest_log.opened);
642:             assert(manifest_log.writing);
643:             assert(manifest_log.blocks_closed <= manifest_log.blocks.count);
644: 
645:             manifest_log.writes_pending -= 1;
646: 
647:             if (manifest_log.writes_pending == 0) {
648:                 for (0..manifest_log.blocks_closed) |_| manifest_log.blocks.advance_head();
649:                 manifest_log.blocks_closed = 0;
650: 
651:                 if (manifest_log.blocks.count == 0) {
652:                     assert(manifest_log.entry_count == 0);
653:                 } else {
654:                     assert(manifest_log.blocks.count == 1);
655:                     assert(manifest_log.entry_count < schema.ManifestNode.entry_count_max);
656:                 }
657: 
658:                 manifest_log.flush_done();
659:             }
