662:         /// `compact` does not close a partial block; that is only necessary during `checkpoint`.
663:         ///
664:         /// The (production) block size is large, so the number of blocks compacted per half-bar is
665:         /// relatively small (e.g. ~4). We read them in sequence rather than parallel to spread the
666:         /// work more evenly across the half-bar's beats.
667:         // TODO Make sure block reservation cannot fail — before compaction begins verify that
668:         // enough free blocks are available for all reservations.
669:         pub fn compact(manifest_log: *ManifestLog, callback: Callback, op: u64) void {
670:             assert(manifest_log.opened);
671:             assert(!manifest_log.reading);
672:             assert(!manifest_log.writing);
673:             assert(manifest_log.read_callback == null);
674:             assert(manifest_log.write_callback == null);
675:             assert(manifest_log.grid_reservation == null);
676:             assert(manifest_log.blocks.count ==
677:                 manifest_log.blocks_closed + @intFromBool(manifest_log.entry_count > 0));
678:             assert(manifest_log.compact_blocks == null);
679:             assert(op >= constants.lsm_compaction_ops);
680:             assert(!manifest_log.superblock.working.vsr_state.op_compacted(op));
681: 
682:             // TODO: Currently manifest compaction is hardcoded to run on the last beat of each
683:             // half-bar.
684:             // This is because otherwise it would mess with our grid reserve / forfeit ordering,
685:             // since we now reserve / forfeit per beat.
686:             assert((op + 1) % @divExact(constants.lsm_compaction_ops, 2) == 0);
687: 
688:             manifest_log.grid.trace.start(.compact_manifest);
689: 
690:             manifest_log.compact_blocks = @min(
691:                 manifest_log.pace.half_bar_compact_blocks(.{
692:                     .log_blocks_count = @intCast(manifest_log.log_block_checksums.count),
693:                     .tables_count = manifest_log.table_extents.count(),
694:                 }),
695:                 // Never compact closed blocks. (They haven't even been written yet.)
696:                 manifest_log.log_block_checksums.count - manifest_log.blocks_closed,
697:             );
698:             assert(manifest_log.compact_blocks.? <= manifest_log.pace.half_bar_compact_blocks_max);
699: 
700:             manifest_log.grid_reservation = manifest_log.grid.reserve(

700:             manifest_log.grid_reservation = manifest_log.grid.reserve(
701:                 manifest_log.compact_blocks.? +
702:                     manifest_log.pace.half_bar_append_blocks_max,
703:             );
704: 
705:             manifest_log.read_callback = callback;
706:             manifest_log.flush(compact_next_block);
707:         }
