709:         fn compact_next_block(manifest_log: *ManifestLog) void {
710:             assert(manifest_log.opened);
711:             assert(!manifest_log.reading);
712:             assert(!manifest_log.writing);
713:             assert(manifest_log.read_callback != null);
714:             assert(manifest_log.grid_reservation != null);
715: 
716:             const compact_blocks = manifest_log.compact_blocks.?;
717:             if (compact_blocks == 0) {
718:                 manifest_log.compact_done_callback();
719:             } else {
720:                 const oldest_checksum = manifest_log.log_block_checksums.head().?;
721:                 const oldest_address = manifest_log.log_block_addresses.head().?;
722:                 assert(oldest_address > 0);
723: 
724:                 manifest_log.compact_blocks.? -= 1;
725:                 manifest_log.reading = true;
726:                 manifest_log.grid.read_block(
727:                     .{ .from_local_or_global_storage = compact_read_block_callback },
728:                     &manifest_log.read,
729:                     oldest_address,
730:                     oldest_checksum,
731:                     .{ .cache_read = true, .cache_write = true },
732:                 );
733:             }
734:         }
