736:         fn compact_read_block_callback(read: *Grid.Read, block: BlockPtrConst) void {
737:             const manifest_log: *ManifestLog = @fieldParentPtr("read", read);
738:             assert(manifest_log.opened);
739:             assert(manifest_log.reading);
740:             assert(!manifest_log.writing);
741:             assert(manifest_log.read_callback != null);
742:             assert(manifest_log.grid_reservation != null);
743: 
744:             const oldest_checksum = manifest_log.log_block_checksums.pop().?;
745:             const oldest_address = manifest_log.log_block_addresses.pop().?;
746:             verify_block(block, oldest_checksum, oldest_address);
747: 
748:             const block_schema = schema.ManifestNode.from(block);
749:             assert(block_schema.entry_count > 0);
750:             assert(block_schema.entry_count <= schema.ManifestNode.entry_count_max);
751: 
752:             var frees: u32 = 0;
753:             for (
754:                 block_schema.tables_const(block),
755:                 0..block_schema.entry_count,
756:             ) |*table, entry_index| {
757:                 const entry: u32 = @intCast(entry_index);
758:                 switch (table.label.event) {
759:                     .reserved => unreachable,
760:                     // Append the table, updating the table extent:
761:                     .insert,
762:                     .update,
763:                     => {
764:                         // Update the extent if the table is the latest version.
765:                         // We must iterate entries in forward order to drop the extent here.
766:                         // Otherwise, stale versions earlier in the block may reappear.
767:                         if (std.meta.eql(
768:                             manifest_log.table_extents.get(table.address),
769:                             .{ .block = oldest_address, .entry = entry },
770:                         )) {
771:                             // Append the table, updating the table extent:
772:                             manifest_log.append_internal(table);
773:                         } else {
774:                             // Either:
775:                             // - This is not the latest insert for this table, so it can be dropped.
776:                             // - The table was removed some time after this insert.
777:                             frees += 1;
778:                         }
779:                     },
780:                     // Since we compact oldest blocks first, we know that we have already
781:                     // compacted all inserts that were eclipsed by this remove, so this remove
782:                     // can now be safely dropped.
783:                     .remove => frees += 1,
784:                 }
785:             }
786: 
787:             log.debug("{}: compacted: checksum={x:0>32} address={} free={}/{}", .{
788:                 manifest_log.superblock.replica_index.?,
789:                 oldest_checksum,
790:                 oldest_address,
791:                 frees,
792:                 block_schema.entry_count,
793:             });
794: 
795:             // Blocks are compacted in sequence – not skipped, even if no entries will be freed.
796:             // (That should be rare though, since blocks are large.)
797:             // This is necessary to update the block's "previous block" pointer in the header.
798:             maybe(frees == 0);
799:             assert(manifest_log.blocks_closed <= manifest_log.pace.half_bar_compact_blocks_max);
800: 
801:             manifest_log.grid.release(&.{oldest_address});
802:             manifest_log.reading = false;
803: 
804:             manifest_log.compact_next_block();
805:         }
