257: // ươ auto-fill: if coda added and nucleus has uo/uô, auto-fill w modifier
258: fn autoFillUO(s: *State) void {
259:     const r = computeRegions(s);
260:     if (!r.has_nucleus) return;
261:     if (r.coda_start >= s.len) return; // no coda
262: 
263:     // Look for u and o adjacent in nucleus
264:     var i = r.nucleus_start;
265:     while (i < r.nucleus_end) : (i += 1) {
266:         const cur_lo = toLower(s.spans[i].base);
267:         const next_lo = toLower(s.spans[i + 1].base);
268: 
269:         if (cur_lo == 'u' and next_lo == 'o') {
270:             // If one has 'w' modifier and the other doesn't, auto-fill
271:             const u_has_w = s.spans[i].modifier == 'w';
272:             const o_has_w = s.spans[i + 1].modifier == 'w';
273:             // Also check for ô (modifier 'o')
274:             const o_has_hat = s.spans[i + 1].modifier == 'o';
275: 
276:             if (u_has_w and !o_has_w and !o_has_hat) {
277:                 s.spans[i + 1].modifier = 'w';
278:             } else if (o_has_w and !u_has_w) {
279:                 s.spans[i].modifier = 'w';
280:             } else if (o_has_hat and !u_has_w) {
281:                 // uô → ươ: set w on u, keep ô as is... actually ươ
282:                 // If o has hat (ô), and we want ươ, we need w on both? No.
283:                 // Actually: ươ = u+w, o+w. The hat form uô is separate.
284:                 // Only auto-fill when modifier is 'w'.
